mapper.select:
SELECT b.*, u.real_name as admin_name FROM building b LEFT JOIN user u ON b.admin_id = u.id
AND b.name LIKE CONCAT('%', #{name}, '%')
ORDER BY b.id DESC LIMIT #{offset}, #{limit}

mapper.update:
UPDATE building
name = #{name}, address = #{address}, floors = #{floors}, admin_id = #{adminId}, description = #{description},
WHERE id = #{id}
